	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for
// terraform plan, showing only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a compact diff summary of the plan, grouped by action type
// and with a summary count at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group changes by action
	changes := make(map[plans.Action][]*addrs.AbsResourceInstance)

	for _, rc := range plan.Changes.Resources {
		// Skip deposed resources and no-op changes
		if rc.DeposedKey != states.NotDeposed || rc.Action == plans.NoOp {
			continue
		}

		changes[rc.Action] = append(changes[rc.Action], &rc.Addr)
	}

	// If there are no changes, return empty string
	if len(changes) == 0 {
		return ""
	}

	var output strings.Builder

	// Define the order of actions for consistent output
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Delete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
	}

	// Track total counts
	totalCount := 0

	// Output changes grouped by action
	for _, action := range actionOrder {
		addresses, exists := changes[action]
		if !exists || len(addresses) == 0 {
			continue
		}

		// Sort addresses for consistent output
		sort.Slice(addresses, func(i, j int) bool {
			return addresses[i].String() < addresses[j].String()
		})

		// Write action header
		actionName := actionName(action)
		output.WriteString(fmt.Sprintf("%s (%d):\n", actionName, len(addresses)))

		// Write each resource change
		for _, addr := range addresses {
			output.WriteString(fmt.Sprintf("  [%s] %s.%s\n",
				shortActionSymbol(action),
				addr.Resource.Resource.Type,
				addr.Resource.Resource.Name,
			))
			totalCount++
		}
	}

	// Add summary
	output.WriteString(fmt.Sprintf("\nPlan: %d resource changes\n", totalCount))

	return output.String()
}

// actionName returns a human-readable name for an action
func actionName(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.CreateThenForget:
		return "Create then forget"
	case plans.NoOp:
		return "No-op"
	default:
		return "Unknown"
	}
}

// shortActionSymbol returns a short symbol for an action
func shortActionSymbol(action plans.Action) string {
	switch action {
	case plans.Create:
		return "+"
	case plans.Update:
		return "~"
	case plans.Delete:
		return "-"
	case plans.DeleteThenCreate:
		return "∓"
	case plans.CreateThenDelete:
		return "±"
	case plans.Read:
		return "<="
	case plans.Forget:
		return "."
	case plans.CreateThenForget:
		return "⨥"
	case plans.NoOp:
		return " "
	default:
		return "?"
	}
}

